import{_ as e,o,c as t,a}from"./app.1f0d3914.js";const g=JSON.parse(`{"title":"TheOrangeWizard v. Quauhtli'n'Mia, Apr 2018","description":"","frontmatter":{},"headers":[{"level":2,"title":"Case","slug":"case","link":"#case","children":[]},{"level":2,"title":"Proceedings","slug":"proceedings","link":"#proceedings","children":[]}],"relativePath":"government/court-cases-precedents/theorangewizard_v_quauhtli_n_mia_apr_2018.md","lastUpdated":1666477380000}`),n={name:"government/court-cases-precedents/theorangewizard_v_quauhtli_n_mia_apr_2018.md"},r=a('<h1 id="theorangewizard-v-quauhtli-n-mia-apr-2018" tabindex="-1">TheOrangeWizard v. Quauhtli&#39;n&#39;Mia, Apr 2018 <a class="header-anchor" href="#theorangewizard-v-quauhtli-n-mia-apr-2018" aria-hidden="true">#</a></h1><h2 id="case" tabindex="-1">Case <a class="header-anchor" href="#case" aria-hidden="true">#</a></h2><p>With BustaNuht presiding, TheOrangeWizard charged Quauhtli&#39;n&#39;Mia with Facilitating Unauthorised Access. Quauhtli&#39;n&#39;Mia was found guilty but not sentenced.</p><h2 id="proceedings" tabindex="-1">Proceedings <a class="header-anchor" href="#proceedings" aria-hidden="true">#</a></h2><p><strong>TheOrangeWizard</strong>:</p><blockquote><p>Quauhtli&#39;n&#39;Mia, I am charging you with unlawfully granting access to the city to LordEmberscar and Modestx, in violation of the executive decision that access for individuals not on Huechat must be approved by a government member</p></blockquote><p><strong>Quauhtli&#39;n&#39;Mia</strong>:</p><blockquote><p>I can account for ember, but I dont know modest O-o</p></blockquote><p><strong>TheOrangeWizard</strong>:</p><blockquote><p>He was allowed in at the same time as Emberscar</p></blockquote><p><strong>Quauhtli&#39;n&#39;Mia</strong>:</p><blockquote><p>Also, when I let ember I let it fairly known in huechat</p></blockquote><blockquote><p>what?</p></blockquote><blockquote><p>No he wasnt lol</p></blockquote><blockquote><p>when ember arrived only he was here</p></blockquote><p><strong>GDAN</strong>:</p><blockquote><p>ModestX is a newfriend i was talking to them earlier today when they started hitting snitches</p></blockquote><p><strong>TheOrangeWizard</strong>:</p><blockquote><p>I know he&#39;s a newfriend, that&#39;s why LordEmberscar came here in the first place, to show Modestx in</p></blockquote><p><strong>Quauhtli&#39;n&#39;Mia</strong>:</p><blockquote><p>thats not what he told me, or what I remember</p></blockquote><blockquote><p>me and him were pming eachother about how lex died and how he insided them; and then I asked him if he could join us and he started on his way</p></blockquote><blockquote><p>When he got here it was only him.</p></blockquote><blockquote><p>You were outside with someone when he was here too</p></blockquote><blockquote><p>you were clearing grass or something outside the walls</p></blockquote><blockquote><p>he was in your face</p></blockquote><p><strong>TheOrangeWizard</strong>:</p><blockquote><p>Please choose a judge for the trial</p></blockquote><p><strong>Quauhtli&#39;n&#39;Mia</strong>:</p><blockquote><p>BustaNuht ?</p></blockquote><blockquote><p>would you be my judge?</p></blockquote><p><strong>BustaNuht</strong>:</p><blockquote><p>it would be an honor</p></blockquote><blockquote><p>the plaintiff starts with their opening statement</p></blockquote><p><strong>TheOrangeWizard</strong>:</p><blockquote><p>Quau invited and let LordEmberscar into NYC without government approval, violating the directive that approval must be given to anyone not on huechat. I&#39;ll drop the charge regarding Modestx seeing as I&#39;m not sure on the details.</p></blockquote><blockquote><p>I believe this is a serious offence that undermines the security of the city and should be punished with fines and/or end time.</p></blockquote><p><strong>Quauhtli&#39;n&#39;Mia</strong>:</p><blockquote><p>Well I did what I did obviously; and i dont quiite rmember this law but im going to assume its a law because you said so and because i have terrible memory</p></blockquote><blockquote><p>HOWEEVAARR Not only were you among other councillors present during the coming of ember</p></blockquote><blockquote><p>I also announced his coming in the discord here In which; bg said he was fine; and I think you did too</p></blockquote><blockquote><p>now it&#39;d be pretty understandeable sueing me like, yesterday for it</p></blockquote><blockquote><p>but now i b scratchin my noggy cuz its like a full day l8r</p></blockquote><p><strong>TheOrangeWizard</strong>:</p><blockquote><p>I attempted to do so but you weren&#39;t here and other people had other trials</p></blockquote><p><strong>Quauhtli&#39;n&#39;Mia</strong>:</p><blockquote><p>but the other several points stand</p></blockquote><blockquote><p>It was either general or citizenry</p></blockquote><blockquote><p>lemme check</p></blockquote><blockquote><p>Oh SPIDER did it for me</p></blockquote><blockquote><p>he pinged government</p></blockquote><blockquote><p>and you came on</p></blockquote><blockquote><p>Oh woops bg said yes but your &quot;no&#39; still stood</p></blockquote><blockquote><p>is it still a No?</p></blockquote><blockquote><p>Cus ember DID help inside laconia/Lex</p></blockquote><blockquote><p>Regardless you were present during the whole time ember came in</p></blockquote><blockquote><p>we were even in Local chat</p></blockquote><blockquote><p>At any givin moment you couldve hollar&#39;d out and told me to stop and him to leave</p></blockquote><blockquote><p>ofcourse that didnt quite happen.</p></blockquote><blockquote><p>Now I can agree; a law&#39;s a law.</p></blockquote><blockquote><p>I kind of remember when you guys announced now</p></blockquote><blockquote><p>back when what&#39;s his name came into town and tried to assasiante bg i think?</p></blockquote><p><strong>BustaNuht</strong>:</p><blockquote><p>yes</p></blockquote><p><strong>Quauhtli&#39;n&#39;Mia</strong>:</p><blockquote><p>ye yee I remember</p></blockquote><blockquote><p>Welp thats my only defense \u{1F61B}</p></blockquote><p><strong>BustaNuht</strong>:</p><blockquote><p>okay</p></blockquote><blockquote><p>TheOrangeWizard do you have anything to say in response?</p></blockquote><p><strong>TheOrangeWizard</strong>:</p><blockquote><p>Modestx is a newfriend that Emberscar brought along, I&#39;m ignoring him for the purposes of this case</p></blockquote><blockquote><p>Quau&#39;s decision to invite Emberscar without permission, and then neglecting to tell anyone, in my opinion constitutes a violation of the law.</p></blockquote><p><strong>Quauhtli&#39;n&#39;Mia</strong>:</p><blockquote><p>I low-key told everyone my dood</p></blockquote><blockquote><p>\u{1F937}\u{1F3FD}</p></blockquote><p><strong>TheOrangeWizard</strong>:</p><blockquote><p>where</p></blockquote><p><strong>Quauhtli&#39;n&#39;Mia</strong>:</p><blockquote><p>In huechat and in general</p></blockquote><blockquote><p>Again; you were in huechat AND active the moment he came and the moment I told people I wanted to bring ember over</p></blockquote><blockquote><p>you were cutting a bunch of grass outside of the walls and ember walked by you</p></blockquote><p><strong>TheOrangeWizard</strong>:</p><blockquote><p>I was completely unaware of this until he showed up at the gate</p></blockquote><p><strong>Quauhtli&#39;n&#39;Mia</strong>:</p><blockquote><p>Not my fault you dont pay attention my dude</p></blockquote><blockquote><p>The ping for the whole gove made by string in general happened BEFORE that too</p></blockquote><blockquote><p>so you HAD to have known it happening</p></blockquote><blockquote><p>or atleast; in the back of your head?</p></blockquote><blockquote><p>Why didnt you just outright tell him to leave or atleast tell me to tell him to leave</p></blockquote><blockquote><p>when all of this was going on?</p></blockquote><p><strong>TheOrangeWizard</strong>:</p><blockquote><p><a href="https://cdn.discordapp.com/attachments/348687557455904778/433856446409736193/emberscar.png" target="_blank" rel="noreferrer">https://cdn.discordapp.com/attachments/348687557455904778/433856446409736193/emberscar.png</a></p></blockquote><p><strong>Quauhtli&#39;n&#39;Mia</strong>:</p><blockquote><p>Cuz wing was around and active during this too</p></blockquote><p><strong>TheOrangeWizard</strong>:</p><blockquote><p>I explicitly said no</p></blockquote><p><strong>Quauhtli&#39;n&#39;Mia</strong>:</p><blockquote><p>Bg said he was fine; but he said it was your final word</p></blockquote><blockquote><p>and I wasnt sure what your final word was; so I assumed you&#39;d tell me or him to leave \u{1F615}</p></blockquote><blockquote><p>which didnt happen</p></blockquote><p><strong>TheOrangeWizard</strong>:</p><blockquote><p>BustaNuht, This is going around in circles, please make a judgement</p></blockquote><blockquote><p>In my view Quau has been extremely negligent towards the law</p></blockquote><p><strong>BustaNuht</strong>:</p><blockquote><p>so according to these chat logs you offered ember an apartment almost immediately after greeting him/her into the city, and you asked us retroactively if it was okay. Because you did ask the government for approval, I will not place sanctions on you. However this case shall set precedent that any newcomers must receive government approval PRIOR to receiving residence and any citizens who give newcomers an apartment without prior govt approval will be sanctioned.</p></blockquote><blockquote><p><a href="https://cdn.discordapp.com/attachments/348687557455904778/433861835817484290/ember.PNG" target="_blank" rel="noreferrer">https://cdn.discordapp.com/attachments/348687557455904778/433861835817484290/ember.PNG</a></p></blockquote><p><strong>TheOrangeWizard</strong>:</p><blockquote><p>For the purpose of setting precedent, what action will the court take should this occur again?</p></blockquote><p><strong>BustaNuht</strong>:</p><blockquote><p>90 minutes of manual labor</p></blockquote><p><strong>SpiderString</strong>:</p><blockquote><p>I only just saw this now, but for prosperity: My ping to the government was after Quauh had logged off and shown emberscar around, not before. Ember had asked for the coords to bring some newfriend to Yoahtl. I didn&#39;t give them, but he somehow got here anyway. Sometime between him asking and showing up was when I pinged gov&#39;t.</p></blockquote><blockquote><p>Also what may or may not be worth noting, ember managed to get on huechat and claims Orange added him. idk if that&#39;s true or not.</p></blockquote><blockquote><p>April 10th, CST Quauh is online and invites ember, later on in the log ember leaves saying he &quot;may return but probably not&quot;</p></blockquote><blockquote><p><a href="https://cdn.discordapp.com/attachments/348687557455904778/433867618357608448/unknown.png" target="_blank" rel="noreferrer">https://cdn.discordapp.com/attachments/348687557455904778/433867618357608448/unknown.png</a></p></blockquote><blockquote><p>April 11th, CST, Quauh is offline and ember asks me for coords, where I refuse.</p></blockquote><blockquote><p><a href="https://cdn.discordapp.com/attachments/348687557455904778/433867700276559882/unknown.png" target="_blank" rel="noreferrer">https://cdn.discordapp.com/attachments/348687557455904778/433867700276559882/unknown.png</a></p></blockquote><blockquote><p>Same day, ember and modest show up at gate</p></blockquote><blockquote><p><a href="https://cdn.discordapp.com/attachments/348687557455904778/433867935858163712/unknown.png" target="_blank" rel="noreferrer">https://cdn.discordapp.com/attachments/348687557455904778/433867935858163712/unknown.png</a></p></blockquote><p><strong>Quauhtli&#39;n&#39;Mia</strong>:</p><blockquote><p>ember said orange added him?</p></blockquote><blockquote><p>See if I knew these things I wouldve just payed the fine \u{1F615}</p></blockquote><p><strong>SpiderString</strong>:</p><blockquote><p><a href="https://cdn.discordapp.com/attachments/348687557455904778/433868179794690058/unknown.png" target="_blank" rel="noreferrer">https://cdn.discordapp.com/attachments/348687557455904778/433868179794690058/unknown.png</a></p></blockquote><blockquote><p>Yes, he claimed orange &quot;let him in&quot;, which I took to mean orange added him to hue as I saw him opening the southern gate on his own</p></blockquote><blockquote><p>I may have misinterpreted that.</p></blockquote><p><strong>TheOrangeWizard</strong>:</p><blockquote><p>Yes, I let him in after consulting with the council and defense team</p></blockquote><blockquote><p>This was after Spider&#39;s ping</p></blockquote>',130),i=[r];function u(s,l,p,c,h,d){return o(),t("div",null,i)}const k=e(n,[["render",u]]);export{g as __pageData,k as default};
